// Espera items con fields: date, amount, orders
function toISODate(d) {
  if (!d) return null;

  // Si ya viene YYYY-MM-DD
  if (typeof d === 'string' && /^\d{4}-\d{2}-\d{2}$/.test(d)) return d;

  // Si viene como fecha de Google/Excel tipo "10/1/2024" o "01/10/2024"
  if (typeof d === 'string') {
    const s = d.trim();
    // Intento robusto: split por / o -
    const parts = s.includes('/') ? s.split('/') : s.split('-');
    if (parts.length === 3) {
      // Heurística: si el primer bloque tiene 4 => YYYY-MM-DD
      if (parts[0].length === 4) {
        const [y,m,dd] = parts;
        return `${y.padStart(4,'0')}-${m.padStart(2,'0')}-${dd.padStart(2,'0')}`;
      }
      // Si no: asumimos formato ES dd/mm/yyyy (por estar en España)
      const [dd,mm,yy] = parts;
      if (yy && yy.length === 4) {
        return `${yy}-${mm.padStart(2,'0')}-${dd.padStart(2,'0')}`;
      }
    }
  }

  // Si viene como número (serial)
  if (typeof d === 'number') {
    // Excel serial date (aprox). Google Sheets a veces devuelve serial.
    // 25569 = 1970-01-01 en Excel (con timezone/offsets). Ajuste simple.
    const epoch = new Date(Math.round((d - 25569) * 86400 * 1000));
    return epoch.toISOString().slice(0,10);
  }

  // Último recurso
  const dt = new Date(d);
  if (!isNaN(dt.getTime())) return dt.toISOString().slice(0,10);
  return null;
}

function num(x) {
  if (x === null || x === undefined || x === '') return null;
  const n = Number(x);
  return Number.isFinite(n) ? n : null;
}

const rows = items.map(i => {
  const r = i.json;
  return {
    date: toISODate(r.date),
    amount: num(r.amount),
    orders: num(r.orders ?? 0) ?? 0
  };
});

// Validaciones básicas
const errors = [];
for (const r of rows) {
  if (!r.date) errors.push(`Fecha inválida: ${JSON.stringify(r)}`);
  if (r.amount === null || r.amount < 0) errors.push(`Amount inválido: ${JSON.stringify(r)}`);
  if (r.orders !== null && r.orders < 0) errors.push(`Orders inválido: ${JSON.stringify(r)}`);
}

// Duplicados por fecha
const seen = new Set();
for (const r of rows) {
  if (!r.date) continue;
  if (seen.has(r.date)) errors.push(`Fecha duplicada: ${r.date}`);
  seen.add(r.date);
}

// Ordenar por fecha
rows.sort((a,b) => (a.date < b.date ? -1 : a.date > b.date ? 1 : 0));

// Huecos de fechas (solo warning, no error hard)
const gaps = [];
for (let i=1; i<rows.length; i++) {
  const prev = new Date(rows[i-1].date);
  const cur = new Date(rows[i].date);
  const diffDays = Math.round((cur - prev) / (24*3600*1000));
  if (diffDays > 1) gaps.push({ from: rows[i-1].date, to: rows[i].date, missing: diffDays-1 });
}

const minHistoryDays = 60;
if (rows.length < minHistoryDays) {
  errors.push(`Histórico insuficiente: ${rows.length} días (mínimo ${minHistoryDays})`);
}

return [{
  json: {
    ok: errors.length === 0,
    errors,
    warnings: gaps.length ? [{ type: "DATE_GAPS", gaps }] : [],
    rows,
    meta: {
      rows: rows.length,
      from: rows[0]?.date,
      to: rows[rows.length-1]?.date
    }
  }
}];

const cfg = {};
for (const it of $input.all()) {
  const { key, value } = it.json;
  if (key) cfg[String(key).trim()] = value;
}
return [{ json: { config: cfg } }];

const { rows, meta, config } = $input.first().json;

const forecastDays = Number(config?.forecast_days ?? 30);
const baselineDays = Number(config?.baseline_days ?? 28);
const alertDropPct = Number(config?.alert_drop_pct ?? 15);
const emailTo = String(config?.email_to ?? '');

if (!rows?.length) return [{ json: { ok:false, error:"No rows" } }];

const toDate = (s) => new Date(`${s}T00:00:00Z`);
const iso = (d) => d.toISOString().slice(0,10);
const addDays = (d, n) => new Date(d.getTime() + n*24*3600*1000);
const dow = (d) => d.getUTCDay(); // 0..6 (UTC)

const baseline = rows.slice(Math.max(0, rows.length - baselineDays));
const baselineTotal = baseline.reduce((acc,r)=> acc + Number(r.amount || 0), 0);
const baselineAvgDaily = baselineTotal / Math.max(1, baseline.length);

const sums = Array(7).fill(0);
const counts = Array(7).fill(0);
for (const r of baseline) {
  const d = toDate(r.date);
  const i = dow(d);
  sums[i] += Number(r.amount || 0);
  counts[i] += 1;
}
const dowAvg = sums.map((s,i) => counts[i] ? (s / counts[i]) : baselineAvgDaily);

const lastDate = toDate(rows[rows.length - 1].date);
const modelVersion = `dow_avg_baseline_${baselineDays}d_v1`;
const runAt = new Date().toISOString().slice(0,19).replace('T',' ');
const createdAt = runAt;
const runId = `${modelVersion}_${runAt.replace(/[- :]/g,'')}`;
const executionId = $execution.id ?? null;

const forecast = [];
for (let i=1; i<=forecastDays; i++) {
  const d = addDays(lastDate, i);
  const pred = dowAvg[dow(d)];
  forecast.push({
    run_id: runId,
    run_at: runAt,
    execution_id: executionId,
    date: iso(d),
    predicted_amount: Math.round(pred * 100) / 100,
    model_version: modelVersion,
    created_at: createdAt
  });
}

const forecastAvgDaily = forecast.reduce((a,r)=>a + r.predicted_amount, 0) / forecast.length;
const dropPct = baselineAvgDaily > 0
  ? ((baselineAvgDaily - forecastAvgDaily) / baselineAvgDaily) * 100
  : 0;

const alert = dropPct >= alertDropPct;

return [{
  json: {
    ok: true,
    meta,
    email_to: emailTo,
    alert,
    alert_drop_pct: alertDropPct,
    drop_pct: Math.round(dropPct * 100) / 100,
    baseline_days: baseline.length,
    baseline_avg_daily: Math.round(baselineAvgDaily * 100) / 100,
    forecast_days: forecastDays,
    forecast_avg_daily: Math.round(forecastAvgDaily * 100) / 100,
    model_version: modelVersion,
    run_id: runId,
    run_at: runAt,
    execution_id: executionId,
    forecast
  }
}];

// Normalize & Compute (Procurement)

function str(v) {
  return (v ?? '').toString().trim();
}

function lower(v) {
  return str(v).toLowerCase();
}

function num(v) {
  const n = Number(v);
  return Number.isFinite(n) ? n : 0;
}

function pad(n, width = 6) {
  const s = String(n);
  return s.length >= width ? s : '0'.repeat(width - s.length) + s;
}

const body = $input.first().json.body ?? {};

// Requester
const requesterName = str(body.requester?.name);
const requesterEmail = lower(body.requester?.email);
const department = str(body.requester?.department);

// Purchase
const category = lower(body.purchase?.category);
const item = str(body.purchase?.item);
const description = str(body.purchase?.description);
const quantity = num(body.purchase?.quantity);
const unitPrice = num(body.purchase?.unit_price);
const currency = (str(body.purchase?.currency) || 'EUR').toUpperCase();
const vendorPreferred = str(body.purchase?.vendor_preferred);

// Metadata
const costCenter = str(body.metadata?.cost_center);
const urgency = lower(body.metadata?.urgency);
const needBy = str(body.metadata?.need_by); // dejamos string por ahora

// Compute
const total = Math.round(quantity * unitPrice * 100) / 100;

// Approval rules
let approvalLevel = 'AUTO';
if (total > 1500) approvalLevel = 'FINANCE';
else if (total > 300) approvalLevel = 'DEPT_MANAGER';

// Generate request_id (simple, deterministic-ish)
const now = new Date();
const yyyy = now.getUTCFullYear();
const mm = String(now.getUTCMonth() + 1).padStart(2, '0');
const dd = String(now.getUTCDate()).padStart(2, '0');
const rand = Math.floor(Math.random() * 1000000);
const requestId = `PR-${yyyy}${mm}${dd}-${pad(rand, 6)}`;

// Output normalized object
return [
  {
    request_id: requestId,
    created_at: now.toISOString(),
    status: 'RECEIVED',

    requester: {
      name: requesterName,
      email: requesterEmail,
      department,
    },

    purchase: {
      category,
      item,
      description,
      quantity,
      unit_price: unitPrice,
      currency,
      vendor_preferred: vendorPreferred,
      total,
    },

    metadata: {
      cost_center: costCenter,
      urgency,
      need_by: needBy,
    },

    routing: {
      approval_level: approvalLevel,
      thresholds: { auto: 300, manager: 1500 },
    },
  },
];

const item = $input.first().json;

const requestId = item.request_id;

// “Secreto” simple (luego lo pasamos a env var)
const SECRET = 'PROCUREMENT_DEMO_SECRET';

// Hash simple (determinístico)
function simpleHash(str) {
  let hash = 0;
  for (let i = 0; i < str.length; i++) {
    hash = (hash << 5) - hash + str.charCodeAt(i);
    hash |= 0;
  }
  return Math.abs(hash).toString(36);
}

const approvalToken = simpleHash(`${requestId}:${SECRET}`);

return [
  {
    ...item,
    approval_token: approvalToken,
  },
];

const item = $input.first().json;

const q = item.query ?? {};
const requestId = (q.request_id ?? '').toString().trim();
const actionRaw = (q.action ?? '').toString().trim().toLowerCase();
const token = (q.token ?? '').toString().trim();

// Solo permitimos estas acciones
const allowed = new Set(['approve', 'reject']);
const action = allowed.has(actionRaw) ? actionRaw : '';

// Debe ser el MISMO SECRET que en el WF 1 (Generate Approval Token)
const SECRET = 'PROCUREMENT_DEMO_SECRET';

// Hash simple (mismo algoritmo que en WF1)
function simpleHash(str) {
  let hash = 0;
  for (let i = 0; i < str.length; i++) {
    hash = (hash << 5) - hash + str.charCodeAt(i);
    hash |= 0;
  }
  return Math.abs(hash).toString(36);
}

const expectedToken = requestId ? simpleHash(`${requestId}:${SECRET}`) : '';
const tokenValid = !!requestId && !!token && token === expectedToken;

const ok = !!requestId && !!action && tokenValid;

return [{
  ...item,
  request_id: requestId,
  action,
  token,
  expected_token: expectedToken,   // solo para debug, luego lo quitamos
  is_valid: ok,
  errors: {
    missing_request_id: !requestId,
    invalid_action: !action,
    token_invalid: !tokenValid,
  }
}];

const data = $input.first().json.data

const regex = /https?:\/\/[^\/]+/g

const urls = data.match(regex)

return urls.map(url => ({json: {url: url}}))

const data = $json.data

const emailRegex = /[a-zA-Z0-9._%+-]+@[a-zA-Z0-9.-]+\.(?!png|jpg|gif|jpeg)[a-zA-Z]{2,}/g

const emails = data.match(emailRegex)

return {json: {emails: emails}}

const msg = ($input.first().json.body?.message || "").toLowerCase();

let score = 0;

const hasAny = (arr) => arr.some(w => msg.includes(w));

if (hasAny(["urgente","esta semana","mañana","ya","cuanto antes"])) score += 3;
if (hasAny(["demo","llamada","reunión","reunion","agendar","calendario"])) score += 3;
if (hasAny(["presupuesto","precio","coste","costo","tarifa","cuánto","cuanto"])) score += 2;
if (hasAny(["crm","whatsapp","zapier","hubspot","pipeline","automatizar","integración","integracion"])) score += 1;
if (msg.length < 20) score -= 1;

let temperature = "cold";
if (score >= 5) temperature = "hot";
else if (score >= 2) temperature = "warm";

const confidence = Math.max(0.4, Math.min(0.95, 0.5 + score * 0.08));

return [{
  ...$input.first().json,
  source_kind: $input.first().json.source_kind ?? "web",
  lead: {
    name: $input.first().json.body?.name,
    email: $input.first().json.body?.email,
    message: $input.first().json.body?.message,
  },
  scoring: {
    score,
    temperature,
    confidence: Number(confidence.toFixed(2)),
  }
}];

const item = $input.first().json;

// reply completo del modelo (HTML o texto)
const reply = (item.reply || "").trim();

// intent detectado previamente (meeting | budget | info | etc.)
const intent = (item.intent || "").toLowerCase();

// 1️⃣ Subject por intent (fallback)
let subjectByIntent = "Tech & Investments";

switch (intent) {
  case "meeting":
    subjectByIntent = "Coordinemos una reunión sobre automatización";
    break;
  case "budget":
    subjectByIntent = "Propuesta y presupuesto de automatización";
    break;
  case "info":
    subjectByIntent = "Información sobre soluciones de automatización";
    break;
}

// 2️⃣ Subject final
let subject = subjectByIntent;
let body = reply;

// 3️⃣ Si la IA devuelve "Asunto: xxx", tiene prioridad
const m = reply.match(/^Asunto:\s*(.+)\n+/i);
if (m) {
  subject = m[1].trim();
  body = reply.replace(/^Asunto:\s*.+\n+/i, "").trim();
}

// 4️⃣ Destinatario
const to = item.email;

// 5️⃣ Salida para Gmail
return [{
  json: {
    email_to: to,
    email_subject: subject,
    email_body: body, // HTML generado por la IA
  }
}];

const item = $input.first().json;

function pick(...values) {
  for (const value of values) {
    if (value !== undefined && value !== null && value !== '') {
      return value;
    }
  }
  return null;
}

function buildUtmFields(sourceKind, payload = item) {
  const serviceSlug = pick(payload.service_slug, payload.serviceSlug, payload.playbook, payload.recommended_service);
  const isInboundWeb = sourceKind === 'web' || sourceKind === 'email' || sourceKind === 'whatsapp';
  return {
    serviceSlug,
    utmSource: pick(payload.utmSource, payload.utm_source, isInboundWeb ? 'tech_investments' : 'lead_ops'),
    utmMedium: pick(payload.utmMedium, payload.utm_medium, isInboundWeb ? sourceKind : 'automation'),
    utmCampaign: pick(payload.utmCampaign, payload.utm_campaign, isInboundWeb ? 'tech_investments_inbound' : 'lead_ops_to_crm'),
    utmTerm: pick(payload.utmTerm, payload.utm_term, serviceSlug),
    utmContent: pick(payload.utmContent, payload.utm_content, sourceKind),
  };
}

function buildWebOrEmailPayload(sourceKind) {
  const iaNotes = {
    origin: sourceKind,
    name: item.name ?? null,
    email: item.email ?? null,
    message: item.message ?? null,
    reply: item.reply ?? null,
    intent: item.intent ?? null,
    temperature: item.temperature ?? null,
    confidence: item.confidence ?? null,
    subject: item.subject ?? null,
  };
  const utm = buildUtmFields(sourceKind);

  return {
    email: item.email,
    name: item.name,
    company: item.company ?? null,
    phone: item.phone ?? null,
    website: item.website ?? null,
    message: item.message ?? null,
    notes: null,
    iaNotes: JSON.stringify(iaNotes),
    temperature: item.temperature ?? 'cold',
    intent: item.intent ?? 'info',
    source: sourceKind,
    ...utm,
    estimatedValue: null,
    nextActionAt: null,
    lostReason: null,
    serviceIds: [],
  };
}

function buildWhatsAppPayload(sourceKind) {
  const inbound = item.body && typeof item.body === 'object' ? item.body : item;
  const waId = pick(inbound.wa_id, inbound.waId, inbound.sender, inbound.from);
  const contactName = pick(inbound.contact_name, inbound.contactName, inbound.name, inbound.profile?.name);
  const messageText = pick(inbound.text, inbound.message, inbound.body, inbound.message_text);
  const email = pick(
    inbound.email,
    inbound.contact?.email,
    waId ? 'wa-' + String(waId).replace(/[^a-zA-Z0-9]/g, '') + '@whatsapp.local' : null,
  );
  const name = pick(contactName, waId, 'WhatsApp Lead');
  const phone = pick(inbound.phone, inbound.sender, inbound.from, waId);
  const iaNotes = {
    origin: sourceKind,
    waId,
    sender: inbound.sender ?? null,
    contactName,
    messageId: inbound.message_id ?? inbound.messageId ?? null,
    message: messageText ?? null,
  };
  const utm = buildUtmFields(sourceKind, inbound);

  return {
    email,
    name,
    company: null,
    phone,
    website: null,
    message: messageText ?? null,
    notes: null,
    iaNotes: JSON.stringify(iaNotes),
    temperature: 'warm',
    intent: 'info',
    source: sourceKind,
    ...utm,
    estimatedValue: null,
    nextActionAt: null,
    lostReason: null,
    serviceIds: [],
  };
}

function mergeCrmPayload(sourceKind, payload) {
  const utm = buildUtmFields(sourceKind, { ...item, ...payload });
  return {
    ...payload,
    ...utm,
  };
}

const sourceKindRaw = item.source_kind || item.body?.source_kind || item.source || item.body?.source || item.channel || item.body?.channel || item.provider || item.body?.provider || 'web';
const sourceKind = sourceKindRaw === 'whatsapp_cloud_api' ? 'whatsapp' : sourceKindRaw;
const inboundPayload = item.body?.crm_payload ?? item.crm_payload;
if (inboundPayload && typeof inboundPayload === 'object') {
  return [{ json: { ...item, crm_payload: mergeCrmPayload(sourceKind, inboundPayload) } }];
}

if (sourceKind === 'whatsapp') {
  return [{
    json: {
      ...item,
      crm_payload: buildWhatsAppPayload(sourceKind),
    }
  }];
}

return [{
  json: {
    ...item,
    crm_payload: buildWebOrEmailPayload(sourceKind),
  }
}];

const item = $input.first().json;

function fixMojibake(s = "") {
  s = String(s);
  if (!/(Ã.|Â.|â€™|â€œ|â€|�)/.test(s)) return s;

  try {
    const bytes = Uint8Array.from(s, c => c.charCodeAt(0) & 0xff);
    const decoded = new TextDecoder("utf-8", { fatal: false }).decode(bytes);
    return decoded;
  } catch (e) {
    return s;
  }
}

function decodeLatinEntities(s = "") {
  return s
    .replace(/&aacute;/gi, "á")
    .replace(/&eacute;/gi, "é")
    .replace(/&iacute;/gi, "í")
    .replace(/&oacute;/gi, "ó")
    .replace(/&uacute;/gi, "ú")
    .replace(/&ntilde;/gi, "ñ")
    .replace(/&uuml;/gi, "ü")
    .replace(/&ccedil;/gi, "ç")
    .replace(/&Aacute;/g, "Á")
    .replace(/&Eacute;/g, "É")
    .replace(/&Iacute;/g, "Í")
    .replace(/&Oacute;/g, "Ó")
    .replace(/&Uacute;/g, "Ú")
    .replace(/&Ntilde;/g, "Ñ");
}

function htmlToText(s) {
  return String(s)
    .replace(/<br\s*\/?>/gi, "\n")
    .replace(/<\/p>/gi, "\n")
    .replace(/<[^>]+>/g, "")
    .replace(/&nbsp;/g, " ")
    .replace(/&amp;/g, "&")
    .replace(/&lt;/g, "<")
    .replace(/&gt;/g, ">")
    .replace(/&#39;/g, "'")
    .replace(/&quot;/g, '"');
}

const subject = fixMojibake(item.subject || "");
const subjectLower = subject.toLowerCase();
const isLead =
  subjectLower.includes("nuevo mensaje de contacto") ||
  subjectLower.includes("mensaje de contacto") ||
  subjectLower.includes("contacto");

if (!isLead) {
  return [{ ...item, isLead: false, reason: "Not lead", source_kind: "email" }];
}

const textHtml = decodeLatinEntities(fixMojibake(item.textHtml || ""));
const textPlain = decodeLatinEntities(fixMojibake(item.textPlain || ""));
const text = textHtml ? htmlToText(textHtml) : textPlain;

function pick(re) {
  const m = text.match(re);
  return m ? m[1].trim() : "";
}

const nombre = pick(/Nombre:\s*(.+)/i);
const apellidos = pick(/Apellidos:\s*(.+)/i);
const email = pick(/Email:\s*([^\s]+)/i);
const telefono = pick(/Tel[eé]fono:\s*([0-9+\s-]+)/i);
const mensaje = pick(/Mensaje:\s*([\s\S]+)/i);

const fullName = [nombre, apellidos].filter(Boolean).join(" ").trim() || nombre || "Lead";

return [{
  isLead: true,
  source_kind: "email",
  subject,
  body: {
    name: fullName,
    email,
    phone: telefono,
    message: mensaje,
  }
}];

const input = $input.first().json;
const requestHeaders = input.headers ?? {};

function normalizeBearer(value) {
  if (value === undefined || value === null) return null;
  const raw = String(value).trim();
  if (!raw) return null;
  return raw.toLowerCase().startsWith('bearer ') ? raw.slice(7).trim() : raw;
}

function getHeader(headers, ...names) {
  for (const name of names) {
    const value = headers[name] ?? headers[name.toLowerCase()] ?? headers[name.toUpperCase()];
    if (value !== undefined && value !== null && String(value).trim() !== '') {
      return value;
    }
  }
  return null;
}

const configuredWebhookToken = (() => {
  try {
    return typeof $env !== 'undefined' ? $env.N8N_WEBHOOK_BEARER_TOKEN : undefined;
  } catch (error) {
    return undefined;
  }
})();
const expectedWebhookToken = normalizeBearer(configuredWebhookToken || 'n8n_webhook_service_token_local');
if (!expectedWebhookToken) {
  throw new Error('N8N_WEBHOOK_BEARER_TOKEN is not configured.');
}

const incomingWebhookToken = normalizeBearer(getHeader(requestHeaders, 'x-n8n-webhook-token', 'x-webhook-token', 'authorization'));
if (!incomingWebhookToken || incomingWebhookToken !== expectedWebhookToken) {
  throw new Error('Unauthorized webhook request.');
}

const body = input.body ?? input;

const phone =
  body.contact?.phone ||
  body.contact?.wa_id ||
  "";

const email =
  body.contact?.email ||
  "";

return [
  {
    json: {
      originalRequest: body,
      headers: input.headers ?? {},
      crmQuery: {
        phone,
        email,
      },
    },
  },
];

const input = $input.first().json ?? {};

const hasHttpError =
  input.error ||
  input.statusCode >= 400 ||
  input.code === 'ERR_BAD_REQUEST' ||
  input.code === 'ERR_BAD_RESPONSE' ||
  input.message?.toLowerCase?.().includes('request failed');

if (hasHttpError) {
  return [
    {
      json: {
        ok: false,
        found: false,
        error_code: 'crm_error',
        message:
          input.response?.body?.message ||
          input.response?.data?.message ||
          input.message ||
          'No se pudo procesar la operación.',
        raw_summary: {
          source: 'crm',
          status: input.statusCode ?? input.response?.status ?? null,
          code: input.code ?? null,
        },
        raw: input,
      },
    },
  ];
}

const contact = input.contact ?? null;
const found = Boolean(contact && contact.id);

if (!found) {
  return [
    {
      json: {
        ok: true,
        found: false,
        source: 'crm',
        contact: null,
        summary: 'No se encontró contacto en CRM.',
        recent_activity: [],
        open_opportunities: [],
        appointments: {
          next: null,
          past: [],
        },
        sales: [],
        flags: {
          needs_human: false,
          do_not_contact: false,
          existing_customer: false,
          has_next_appointment: false,
          has_open_opportunities: false,
          has_sales: false,
        },
        raw: input,
      },
    },
  ];
}

